import{_ as a,o as i,c as r,ag as o}from"./chunks/framework.ByAj6Cie.js";const h=JSON.parse('{"title":"Contribuir","description":"","frontmatter":{},"headers":[],"relativePath":"es/home/contribute.md","filePath":"es/home/contribute.md"}'),n={name:"es/home/contribute.md"};function t(l,e,s,c,u,d){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="contribuir" tabindex="-1">Contribuir <a class="header-anchor" href="#contribuir" aria-label="Permalink to &quot;Contribuir&quot;">​</a></h1><p>Este proyecto es abierto y se mantiene como un manual curado.</p><p>Las contribuciones son bienvenidas, pero se revisan para asegurar claridad, consistencia y calidad.</p><hr><h2 id="vision-general" tabindex="-1">Visión general <a class="header-anchor" href="#vision-general" aria-label="Permalink to &quot;Visión general&quot;">​</a></h2><p>El objetivo de este proyecto es hacer que el conocimiento industrial sea práctico y fácil de entender.</p><p>Para lograrlo, todo el contenido sigue una estructura clara y un estilo definido.</p><hr><h2 id="formas-de-contribuir" tabindex="-1">Formas de contribuir <a class="header-anchor" href="#formas-de-contribuir" aria-label="Permalink to &quot;Formas de contribuir&quot;">​</a></h2><p>Puedes contribuir de diferentes maneras:</p><ul><li>Reportar errores o explicaciones poco claras</li><li>Sugerir mejoras o nuevos temas</li><li>Enviar contenido o ediciones</li></ul><hr><h2 id="como-contribuir" tabindex="-1">Cómo contribuir <a class="header-anchor" href="#como-contribuir" aria-label="Permalink to &quot;Cómo contribuir&quot;">​</a></h2><ol><li>Haz un fork del repositorio</li><li>Crea una nueva rama</li><li>Realiza tus cambios</li><li>Envía un pull request</li></ol><hr><h2 id="que-esperar" tabindex="-1">Qué esperar <a class="header-anchor" href="#que-esperar" aria-label="Permalink to &quot;Qué esperar&quot;">​</a></h2><p>Todas las contribuciones se revisan antes de ser aceptadas.</p><p>Ten en cuenta:</p><ul><li>No todas las contribuciones serán aceptadas</li><li>Los cambios pueden modificarse para ajustarse al estilo y estructura del manual</li><li>Puede proporcionarse retroalimentación</li></ul><p>Este proceso ayuda a mantener la consistencia del proyecto.</p><hr><h2 id="lineamientos" tabindex="-1">Lineamientos <a class="header-anchor" href="#lineamientos" aria-label="Permalink to &quot;Lineamientos&quot;">​</a></h2><p>Al contribuir, procura:</p><ul><li>Mantener explicaciones claras y prácticas</li><li>Evitar complejidad innecesaria</li><li>Seguir la estructura de las páginas existentes</li><li>Enfocarte en la comprensión y aplicación, no solo en la teoría</li></ul><hr><h2 id="enfoque-del-contenido" tabindex="-1">Enfoque del contenido <a class="header-anchor" href="#enfoque-del-contenido" aria-label="Permalink to &quot;Enfoque del contenido&quot;">​</a></h2><p>Este manual está diseñado para:</p><ul><li>Explicar conceptos de forma simple y práctica</li><li>Ayudar a tomar decisiones en escenarios reales</li><li>Reducir la brecha entre teoría y aplicación</li></ul><hr><h2 id="nota-final" tabindex="-1">Nota final <a class="header-anchor" href="#nota-final" aria-label="Permalink to &quot;Nota final&quot;">​</a></h2><p>Todas las contribuciones son valiosas, ya sean pequeñas o grandes.</p><p>Incluso reportar un problema o sugerir una mejora ayuda a hacer este proyecto mejor.</p>',32)])])}const m=a(n,[["render",t]]);export{h as __pageData,m as default};
